import { useState } from "react";
import { Link, useLocation } from "react-router-dom";
import { ChevronDown, ChevronRight, LayoutGrid, BookOpen } from "lucide-react";

const Sidebar = () => {
  const [adminOpen, setAdminOpen] = useState(true);
  const [examOpen, setExamOpen] = useState(true);
  const [categoryOpen, setCategoryOpen] = useState(true); // NEW: Category state
  const location = useLocation();

  const isActive = (path) => location.pathname === path;

  return (
    <div className="w-64 h-screen bg-gray-900 text-white flex flex-col">
      {/* Header */}
      <div className="p-4 border-b border-gray-700">
        <h2 className="text-xl font-bold uppercase tracking-tighter">Admin Panel</h2>
      </div>

      {/* Menu */}
      <div className="flex-1 p-4 overflow-y-auto custom-scrollbar">
        {/* Admin Controller Section */}
        <button
          onClick={() => setAdminOpen(!adminOpen)}
          className="flex justify-between items-center w-full py-2 font-semibold hover:text-blue-400 transition-colors"
        >
          <span className="uppercase text-xs tracking-widest text-gray-400">Admin Controller</span>
          {adminOpen ? <ChevronDown size={18} /> : <ChevronRight size={18} />}
        </button>

        {adminOpen && (
          <div className="ml-2 mt-2 space-y-1">
            
            {/* --- EXAM SECTION --- */}
            <div>
              <button
                onClick={() => setExamOpen(!examOpen)}
                className="flex justify-between items-center w-full py-2 px-2 hover:bg-gray-800 rounded-lg transition-all"
              >
                <div className="flex items-center gap-2">
                  <BookOpen size={16} className="text-blue-400" />
                  <span className="text-sm font-medium">Exam</span>
                </div>
                {examOpen ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
              </button>

              {examOpen && (
                <div className="ml-7 mt-1 border-l border-gray-700">
                  <Link
                    to="/dashboard/exam-master"
                    className={`block py-2 px-4 text-xs font-semibold rounded-r-lg transition-all ${
                      isActive("/dashboard/exam-master")
                        ? "bg-blue-600/20 text-blue-400 border-l-2 border-blue-600"
                        : "text-gray-400 hover:text-white hover:bg-gray-800"
                    }`}
                  >
                    Exam Master
                  </Link>
                </div>
              )}
            </div>

            {/* --- CATEGORY SECTION (NEW) --- */}
            <div className="mt-2">
              <button
                onClick={() => setCategoryOpen(!categoryOpen)}
                className="flex justify-between items-center w-full py-2 px-2 hover:bg-gray-800 rounded-lg transition-all"
              >
                <div className="flex items-center gap-2">
                  <LayoutGrid size={16} className="text-emerald-400" />
                  <span className="text-sm font-medium">Category</span>
                </div>
                {categoryOpen ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
              </button>

              {categoryOpen && (
                <div className="ml-7 mt-1 border-l border-gray-700">
                  <Link
                    to="/dashboard/category-master"
                    className={`block py-2 px-4 text-xs font-semibold rounded-r-lg transition-all ${
                      isActive("/dashboard/category-master")
                        ? "bg-emerald-600/20 text-emerald-400 border-l-2 border-emerald-600"
                        : "text-gray-400 hover:text-white hover:bg-gray-800"
                    }`}
                  >
                    Category Master
                  </Link>
                </div>
              )}
            </div>

          </div>
        )}
      </div>
    </div>
  );
};

export default Sidebar;
